const QUESTIONS_ECIH_C2 = [
  { id:80301, domain:2, level:3, question:"During the preparation phase of IH&R, which activity best ensures the incident response team can act quickly?", options:["Developing and regularly testing incident response policies, playbooks, and communication plans","Waiting until an incident is confirmed before assigning any roles or duties to team members","Purchasing forensic tools only after a major breach has already impacted the production systems","Documenting the incident only after recovery so that lessons can be captured for the next event"], correct:0, explanation:"Preparation is proactive; waiting until an incident occurs defeats the purpose of readiness planning." },
  { id:80302, domain:2, level:2, question:"What is the primary purpose of establishing an incident response policy during preparation?", options:["To list every possible malware signature that antivirus tools should detect on the endpoints","To define the scope, authority, roles, and procedures that govern how incidents are handled","To replace the need for a dedicated response team by fully automating all of the response actions","To document the financial losses expected from incidents so that insurance can be purchased later"], correct:1, explanation:"A policy sets scope and authority; it does not enumerate malware signatures, which is a tool function." },
  { id:80303, domain:2, level:1, question:"Which readiness element should the handler verify about the IR team before incidents occur?", options:["That every single employee in the company has administrative rights to all of the critical systems","That all logging has been disabled ahead of time to reduce noise during a future investigation","That team members are trained, roles are defined, and contact and escalation lists are current","That backups are deleted on a regular basis to save storage on the recovery infrastructure used"], correct:2, explanation:"Readiness means trained staff and current contacts; deleting backups or logs harms response." },
  { id:80304, domain:2, level:3, question:"Why should an organization maintain a jump kit or incident response toolkit during preparation?", options:["So responders can avoid documenting any of their actions taken during an active security incident","So the organization can confidently skip the containment phase entirely for most of its incidents","So management is not required to approve any budget for the security operations of the company","So responders have pre-configured trusted tools and media ready to deploy without any delay"], correct:3, explanation:"A jump kit provides ready trusted tools; it does not eliminate documentation or containment." },
  { id:80305, domain:2, level:2, question:"What role does security awareness training play in the preparation phase?", options:["It reduces the likelihood of successful attacks and improves early user reporting of incidents","It guarantees that no phishing email will ever reach any employee inbox in the organization again","It removes the need for technical controls such as firewalls and endpoint protection on the network","It is only useful after an incident to assign blame to the users who happened to be affected by it"], correct:0, explanation:"Training improves prevention and reporting; it does not replace technical controls or assign blame." },
  { id:80306, domain:2, level:3, question:"Which document defines acceptable use of organizational systems and supports handling readiness?", options:["A vendor invoice listing all of the antivirus licenses that were purchased for the endpoints last year","An acceptable use policy that sets clear expectations for user behavior on organizational systems","A marketing brochure describing the company public security certifications and the awards it has won","A random collection of raw log files with no defined retention or review process attached to them"], correct:1, explanation:"An AUP supports readiness by setting user expectations; an invoice does not govern user behavior." },
  { id:80307, domain:2, level:2, question:"What is a key benefit of conducting tabletop exercises during preparation?", options:["They guarantee that no real security incident will ever occur after the exercise has been completed","They fully replace the need for any written incident response procedures or playbooks at all","They test the team response plan and reveal gaps without impacting any live production systems","They are used only to punish the staff members who respond incorrectly during the practice drill"], correct:2, explanation:"Tabletop exercises reveal gaps safely; they do not guarantee incident-free operations afterward." },
  { id:80308, domain:2, level:1, question:"Why establish relationships with legal and HR before an incident during preparation?", options:["So the technical team can transfer full ownership of every single incident to those two departments","So all incidents can be reclassified as non-security matters in order to reduce the overall workload","So the team can conveniently avoid documenting any incidents that involve internal personnel at all","So legal and HR guidance is available immediately when incidents raise those specific concerns"], correct:3, explanation:"Pre-established relationships speed guidance; they do not transfer all ownership away from the team." },
  { id:80309, domain:2, level:3, question:"Which preparation activity helps ensure evidence collected later will be admissible?", options:["Defining forensic procedures and chain-of-custody standards before any incidents actually occur","Deciding in advance to skip all documentation in order to save time during a future investigation","Allowing any staff member to handle the evidence freely without ever recording their own actions","Storing all collected evidence on the same compromised system that is currently under investigation"], correct:0, explanation:"Pre-defined forensic standards support admissibility; skipping documentation undermines it." },
  { id:80310, domain:2, level:2, question:"What is the role of asset inventories in incident preparation?", options:["They eliminate the need to prioritize incidents based on business impact during the triage step","They help responders quickly identify affected systems and their criticality during an incident","They automatically contain any incident that affects a listed asset without human intervention","They are only useful for the finance department and hold no value for the incident handlers at all"], correct:1, explanation:"Inventories speed identification and prioritization; they do not auto-contain incidents themselves." },
  { id:80311, domain:2, level:3, question:"Which element is essential to include in an incident response plan during preparation?", options:["A firm promise that no incident will ever occur if the plan is followed exactly as it is written","A complete list of every website that employees are permitted to visit during their working hours","Clearly defined roles, responsibilities, procedures, and communication and escalation paths","The personal mobile phone numbers of all of the organization external customers and its clients"], correct:2, explanation:"IR plans define roles and procedures; they cannot promise an incident-free environment ever." },
  { id:80312, domain:2, level:2, question:"What is the benefit of pre-authorizing certain containment actions during preparation?", options:["It removes all accountability for whatever actions happen to be taken during the incident response","It guarantees that containment activities will never need to be documented at any point afterward","It ensures that the attacker approves each response action before it is actually carried out by staff","It lets responders act quickly during an incident without waiting for slow approval processes"], correct:3, explanation:"Pre-authorization speeds action while accountability and documentation remain fully required." },
  { id:80313, domain:2, level:1, question:"Why is defining severity levels in advance useful during preparation?", options:["It provides consistent criteria for prioritizing incidents at the time when they actually occur","It ensures that every reported incident automatically receives the maximum severity rating given","It prevents the team from ever having to categorize any of the incidents during the triage phase","It removes the need to assess business impact at any point during the overall incident response"], correct:0, explanation:"Predefined severity levels create consistent prioritization, not automatic maximum ratings." },
  { id:80314, domain:2, level:3, question:"What is the purpose of establishing incident classification categories during preparation?", options:["To ensure that every reported incident is simply ignored until it becomes a public relations issue","To ensure incidents are consistently identified and routed to the correct response process","To remove any need to prioritize incidents according to their actual impact on the business units","To guarantee that the classification of an incident never changes once it has first been assigned"], correct:1, explanation:"Predefined categories ensure consistent routing; they do not remove the need for prioritization." },
  { id:80315, domain:2, level:2, question:"Why should the IR team have defined authority limits established during preparation?", options:["So responders are able to take no actions of any kind without daily executive sign-off in advance","So the attacker can determine the exact boundaries of the response effort well ahead of any incident","So responders know which actions they may take independently and which require prior approval","So documentation of actions taken becomes entirely unnecessary during the whole incident response"], correct:2, explanation:"Defined authority speeds decisions within limits; it does not eliminate documentation duties." },
  { id:80316, domain:2, level:3, question:"What preparation measure supports rapid evidence collection during an incident?", options:["Disabling all system logging so that any future investigation simply produces less data to review","Storing all of the evidence exclusively on the systems that are most likely to become compromised","Waiting until an incident actually occurs before first configuring any monitoring tools whatsoever","Pre-deploying logging, monitoring, and forensic readiness across all of the critical systems"], correct:3, explanation:"Pre-deployed logging enables fast collection; disabling logging cripples any investigation." },
  { id:80317, domain:2, level:2, question:"Which of the following strengthens IR team readiness during preparation?", options:["Regular training, clearly assigned roles, and rehearsed communication procedures for the team","Leaving all of the response roles undefined so that anyone can freely improvise during an incident","Ensuring that the team never once practices its response before facing a real security incident","Restricting all knowledge of the response plan to a single person who is frequently unavailable"], correct:0, explanation:"Training and defined roles build readiness; improvisation and single points of failure hurt it." },
  { id:80318, domain:2, level:1, question:"Which describes the purpose of an incident response retainer with an external firm?", options:["Removing the need for the organization to maintain any internal incident response capability at all in this scenario","Ensuring specialized expertise is available quickly when internal capacity is exceeded during events","Guaranteeing that no incident will ever again require any internal staff involvement of any kind","Allowing the organization to conveniently avoid documenting incidents that are handled by the firm"], correct:1, explanation:"A retainer provides surge expertise; it does not eliminate internal capability or documentation." },
  { id:80319, domain:2, level:3, question:"Why should communication templates be prepared before an incident occurs?", options:["They ensure that stakeholders never actually receive any updates at all during an ongoing incident","They fully replace the need to validate incidents before communicating anything about them to others","They enable fast, consistent, and accurate messaging to stakeholders during an active incident","They guarantee that the media will always report the incident favorably to the general public"], correct:2, explanation:"Templates speed consistent messaging; they do not replace validation or control the media." },
  { id:80320, domain:2, level:2, question:"What is a purpose of maintaining an up-to-date network diagram for readiness?", options:["It ensures that no attacker will ever be able to map the organization internal network in any way","It removes the need to maintain an inventory of the organization critical assets and their owners","It automatically isolates any system on the network the moment that it becomes compromised","It helps responders understand connectivity and identify containment points more quickly"], correct:3, explanation:"Diagrams aid understanding and containment; they do not auto-isolate any compromised systems." },
  { id:80321, domain:2, level:3, question:"What is the main objective of the incident recording and assignment step?", options:["To formally log the reported incident and assign it to an appropriate handler for further action","To immediately wipe all affected systems before any details about the incident have been recorded","To notify the public and the media well before the incident has even been validated internally","To close the incident automatically if no one on the team responds within the first few minutes"], correct:0, explanation:"Recording logs and assigns the incident; wiping systems first destroys needed forensic evidence." },
  { id:80322, domain:2, level:2, question:"Which information is most important to capture when initially recording a reported incident?", options:["The favorite forensic tools of the analyst who simply happens to be on shift at that given moment","Date, time, reporter, affected systems, and a clear description of the observed symptoms","A guaranteed root cause that has been fully determined before any investigation has taken place yet","The complete remediation cost as approved by the finance department prior to any triage of the event"], correct:1, explanation:"Initial records capture facts and symptoms; root cause is unknown until investigation occurs." },
  { id:80323, domain:2, level:1, question:"Why is assigning a unique identifier to each incident record important?", options:["It allows the organization to safely ignore incidents that happen to share a similar identifier number","It automatically resolves the incident in full without requiring any handler involvement whatsoever","It enables consistent tracking, correlation, and reference across the entire incident lifecycle","It prevents any stakeholder from ever being notified about the current status of the given incident"], correct:2, explanation:"Unique IDs enable tracking; they do not auto-resolve incidents or block any notifications." },
  { id:80324, domain:2, level:3, question:"What is a benefit of using a centralized incident tracking system during recording?", options:["It ensures that no two handlers can ever view the same incident information at any point in time","It automatically resolves incidents on its own without requiring any investigation or analysis at all","It removes the need to categorize or prioritize any of the incidents during the later triage phase","It provides a single source of truth for status, ownership, and history of each incident handled"], correct:3, explanation:"Centralized tracking gives one source of truth; it does not auto-resolve any of the incidents." },
  { id:80325, domain:2, level:2, question:"During incident recording, why is capturing the reporting source important?", options:["It allows responders to follow up for details and assess the overall reliability of the report","It ensures the reporter is publicly blamed if the incident later turns out to be a minor one only","It guarantees that the incident is a false positive that can therefore be closed almost immediately","It removes the requirement to validate the reported incident at all during the later triage step"], correct:0, explanation:"Knowing the source aids follow-up and reliability assessment, not blame or skipping triage." },
  { id:80326, domain:2, level:3, question:"What should happen if the initial handler assigned to an incident lacks required expertise?", options:["The incident should simply be closed since the currently assigned handler cannot resolve it alone","The incident should be reassigned or escalated to a handler who has the appropriate skills","The handler should just proceed alone without ever seeking any additional assistance from others","The incident record should be deleted to avoid causing any confusion in the tracking system used"], correct:1, explanation:"Reassignment ensures proper handling; closing or deleting the incident is entirely inappropriate." },
  { id:80327, domain:2, level:2, question:"Why should incident records be kept accurate and up to date throughout the lifecycle?", options:["They exist only to satisfy an external auditor and hold no real operational value for the team","They should be edited only by the attacker who is directly involved in the incident being handled","They support coordination, decision-making, reporting, and the later lessons-learned activities","They must be permanently deleted as soon as the containment phase of the incident first begins"], correct:2, explanation:"Accurate records aid coordination and later review; deleting them loses critical history." },
  { id:80328, domain:2, level:1, question:"Why should incidents be assigned severity or priority at the recording stage when possible?", options:["It guarantees that the incident will require no further triage or any additional analysis at all later","It ensures every incident is treated with completely identical urgency regardless of its real impact","It removes the need to notify any of the stakeholders about the incident at any later point in time","It helps ensure urgent incidents receive prompt attention as they first enter the response queue"], correct:3, explanation:"Early prioritization speeds urgent handling; it does not remove the later triage requirements." },
  { id:80329, domain:2, level:3, question:"What is the risk of poor initial documentation when recording an incident?", options:["Critical details may be lost, hampering investigation, coordination, and any later reporting","The incident will simply resolve itself automatically without any further action being required","The organization will be legally barred from ever investigating the incident that was reported","The attacker will then be required to personally provide all of the missing documentation instead"], correct:0, explanation:"Poor records lose details needed downstream; incidents do not resolve themselves on their own." },
  { id:80330, domain:2, level:2, question:"Why is timestamping entries in an incident record important?", options:["It ensures that the incident record can never be reviewed by any external auditor in the future","It establishes an accurate timeline of when events and actions occurred during the incident","It allows the incident record to simply be closed automatically after a fixed period has elapsed","It fully replaces the need to validate the reported incident during the subsequent triage phase"], correct:1, explanation:"Timestamps build an accurate timeline; they do not auto-close records or bypass the triage step." },
  { id:80331, domain:2, level:3, question:"What should the handler do if new information changes the nature of a recorded incident?", options:["Ignore the new information entirely in order to avoid changing the existing incident record at all","Delete the original record and simply pretend that the incident was never actually reported at all","Update the record and re-triage the incident so it reflects the new and improved understanding","Escalate the matter immediately to the media regardless of what the new information reveals to them"], correct:2, explanation:"New information warrants updating and re-triage; ignoring or deleting records is inappropriate." },
  { id:80332, domain:2, level:2, question:"What is the first action typically taken when a potential incident is reported?", options:["Immediately rebuilding all of the systems that could conceivably be affected by the given event","Publicly disclosing the potential incident to outsiders before any verification has occurred at all","Closing the report without any review whatsoever in order to keep the ticket queue reasonably small","Recording the report with its initial details and assigning it out for further assessment"], correct:3, explanation:"The first step is recording and assigning; premature rebuilds or disclosure are both wrong." },
  { id:80333, domain:2, level:1, question:"What is the primary goal of the incident triage step?", options:["To validate, categorize, and prioritize incidents based on their overall impact and severity","To immediately rebuild all of the affected systems before understanding the incident scope at all","To notify external regulators promptly before even confirming that an incident actually occurred","To permanently delete all of the logs so that the environment simply appears to be clean again"], correct:0, explanation:"Triage validates and prioritizes; premature rebuilds destroy the evidence and lose context." },
  { id:80334, domain:2, level:3, question:"During triage, why must the handler first validate whether a reported event is a true incident?", options:["To ensure the reporter is publicly identified and then held fully accountable for the report made","To avoid expending valuable response resources on false positives and misclassified events","To guarantee that the incident is escalated to the executives regardless of its underlying nature","To immediately begin eradication before any categorization of the event has actually been performed"], correct:1, explanation:"Validation filters false positives; it is not about blaming reporters or skipping response steps." },
  { id:80335, domain:2, level:2, question:"Which factor is most relevant when prioritizing incidents during triage?", options:["The alphabetical order of the hostnames of the systems that first happened to report the alerts","The personal preference of whichever analyst happened to open the incident ticket first that day","The potential business impact and the criticality of the affected assets and the data involved","The age of the hardware involved regardless of the data or the services that it actually hosts"], correct:2, explanation:"Prioritization is impact-driven; hostname order and hardware age are completely irrelevant." },
  { id:80336, domain:2, level:3, question:"How does categorizing an incident during triage benefit the response effort?", options:["It ensures that every single incident is treated identically regardless of its actual type or nature","It removes the requirement to document any of the actions that are taken during the entire response","It automatically restores all of the affected systems without any handler intervention being needed","It routes the incident to the correct procedures, expertise, and appropriate containment strategy"], correct:3, explanation:"Categorization tailors the response; treating all incidents identically is inefficient and risky." },
  { id:80337, domain:2, level:2, question:"When assessing severity during triage, which combination reflects a high-severity incident?", options:["Critical systems affected, sensitive data at risk, and significant operational disruption occurring","A single non-critical workstation that is merely showing a blocked and quarantined benign file only","An informational log entry that shows no confirmed malicious activity or any real user impact at all","A scheduled maintenance window that was already communicated to all of the users well in advance"], correct:0, explanation:"High severity combines critical assets and impact; a quarantined benign file is low severity." },
  { id:80338, domain:2, level:1, question:"Which of the following is an example of proper incident categorization?", options:["Labeling every single reported incident simply as urgent regardless of its actual characteristics","Classifying an event as malware, unauthorized access, denial of service, or a data breach","Assigning categories based purely on the physical color of the affected server chassis in the rack","Choosing a category at complete random so that the incident ticket can be closed a bit more quickly"], correct:1, explanation:"Proper categorization uses meaningful types; random or superficial labels provide no value." },
  { id:80339, domain:2, level:3, question:"How does impact assessment during triage support decision-making?", options:["It determines the specific brand of hardware that should be purchased after the incident concludes","It ensures that low-impact incidents will always receive the highest possible priority for handling","It quantifies the effect on confidentiality, integrity, and availability to help guide the response","It removes the need to notify any of the stakeholders about the incident at any point going forward"], correct:2, explanation:"Impact assessment measures CIA effects to guide response, not hardware purchasing decisions." },
  { id:80340, domain:2, level:2, question:"Why might an incident initially classified as low severity be re-prioritized during triage?", options:["Because severity levels are chosen only once and then can never be changed at any point afterward","Because all low-severity incidents must always be escalated directly to the executives without delay","Because any re-prioritization of an incident is strictly prohibited once it has first been recorded","Because new information may reveal a broader scope or greater impact than was first observed"], correct:3, explanation:"Severity can rise as scope becomes clear; it is not fixed at the first classification." },
  { id:80341, domain:2, level:3, question:"What is the risk of failing to properly triage incidents?", options:["Critical incidents may be delayed while limited resources are spent on trivial and minor events","All of the incidents will simply be resolved automatically without any handler action being needed","The organization will then be legally required to publicly disclose every single minor event it sees","Triage failures always improve the response times measured across the entire incident response team"], correct:0, explanation:"Poor triage misallocates resources, delaying critical incidents; it does not speed response." },
  { id:80342, domain:2, level:2, question:"Which question best helps determine incident priority during triage?", options:["Which of the available analysts happens to have the shortest commute to the main office that day","What business services and data are affected and how severe is the resulting disruption to them","What particular color scheme is currently being used in the organization incident response dashboard","How many completely unrelated tickets were closed by the response team during the previous month"], correct:1, explanation:"Priority hinges on affected services and severity, not analyst commute or dashboard color." },
  { id:80343, domain:2, level:1, question:"What is a false positive in the context of incident triage?", options:["A confirmed breach that has already been fully validated by the incident response team involved","An incident that has already been successfully contained and eradicated by the response team","An alert or report that appears to indicate an incident but is actually entirely benign in nature","A regulatory requirement to notify all affected parties promptly following a confirmed data breach"], correct:2, explanation:"A false positive is a benign event mistaken for an incident, not a confirmed breach." },
  { id:80344, domain:2, level:3, question:"Why is scoping important during the triage of an incident?", options:["It decides which particular vendor will end up supplying replacement hardware after the recovery","It sets the exact marketing message that will eventually be released to the general public later","It guarantees that the incident will always be closed within a fixed number of minutes every time","It determines how many systems, users, and data assets are actually affected by the incident"], correct:3, explanation:"Scoping identifies the extent of impact; it is unrelated to vendor or marketing choices." },
  { id:80345, domain:2, level:2, question:"Which action is appropriate when triage reveals an event is not a genuine incident?", options:["Documenting the finding and closing the event as a false positive with a clear stated rationale","Escalating the benign event immediately to the executive leadership team regardless of its nature","Beginning a full eradication and recovery effort on the systems that were never actually affected","Deleting all of the records so that the event can never be reviewed for detection tuning later on"], correct:0, explanation:"False positives should be documented and closed with rationale, not escalated or erased entirely." },
  { id:80346, domain:2, level:3, question:"How does correlating multiple alerts help during triage?", options:["It ensures that each alert is handled by a completely separate team fully in isolation from others","It can reveal a larger coordinated incident that individual isolated alerts might not clearly show","It guarantees that all of the correlated alerts will turn out to be harmless false positives instead","It removes the need to assess the potential impact of any of the individual alerts being reviewed"], correct:1, explanation:"Correlation can expose a broader incident; isolated handling may miss the bigger picture entirely." },
  { id:80347, domain:2, level:2, question:"Which of the following supports accurate severity assessment during triage?", options:["Relying solely on the specific time of day when the alert was first generated by the tool used","Assigning severity based only on the total number of characters that appear in the given alert name","Evaluating the affected assets, data sensitivity, scope, and operational impact all together","Using one single fixed severity for all of the incidents regardless of their real characteristics"], correct:2, explanation:"Severity considers assets, data, scope, and impact; alert timing alone is clearly insufficient." },
  { id:80348, domain:2, level:1, question:"Why is it important to distinguish an event from an incident during triage?", options:["Events and incidents are entirely identical, so no distinction between them is ever truly necessary","All events must be escalated directly to the executives regardless of their actual nature or impact","Distinguishing them conveniently removes the need to document any of the findings that are made","Not all events are incidents, and treating each event as an incident wastes limited resources"], correct:3, explanation:"Only some events are incidents; conflating the two wastes the team resources unnecessarily." },
  { id:80349, domain:2, level:3, question:"What is the purpose of the notification step in the IH&R process?", options:["To inform the relevant internal and external stakeholders and trigger escalation as required","To publish the full technical details of the breach on public forums almost immediately after it","To ensure that only the attacker involved is informed of the response actions being taken by staff","To deliberately delay all communication until the incident has been completely eradicated first"], correct:0, explanation:"Notification informs stakeholders and escalates; it is not public disclosure of raw details." },
  { id:80350, domain:2, level:2, question:"Why is a defined escalation matrix important during the notification step?", options:["It guarantees that every single reported incident is escalated directly to the CEO without exception","It ensures incidents reach the appropriate decision-makers based on their severity and type","It fully replaces the need to categorize or prioritize any of the incidents during the triage phase","It prevents the technical staff from ever being informed about any of the incident details at all"], correct:1, explanation:"An escalation matrix routes by severity; not every incident should go straight to the CEO." },
  { id:80351, domain:2, level:3, question:"Which obligation may legally require notifying affected parties or regulators after an incident?", options:["The personal preference of whichever incident handler happens to be assigned to the given ticket","The total number of unrelated incidents that were handled by the team earlier during that same year","Data breach notification laws and the regulatory compliance requirements applicable to the data","The specific vendor of the antivirus product that first detected the initial alert on the endpoint"], correct:2, explanation:"Notification obligations come from laws and regulations, not from the handler personal preference." },
  { id:80352, domain:2, level:2, question:"Which stakeholder group typically needs to be notified for an incident with legal implications?", options:["The facilities team, which mainly manages the building access and the routine physical maintenance","The marketing team, which primarily decides the color scheme of the organization public website","The procurement team, which negotiates the prices for the office supplies and the furniture bought","The legal department, which advises on the regulatory and litigation-related obligations involved"], correct:3, explanation:"Legal advises on regulatory obligations; facilities and marketing are not the right owners here." },
  { id:80353, domain:2, level:1, question:"Why is it important to notify management promptly during a significant incident?", options:["Management can authorize resources, approve actions, and make key business risk decisions","Management can personally perform all of the technical containment steps entirely by themselves","Notifying management conveniently removes the need to document the incident at any point afterward","Prompt notification guarantees that the incident will not require any recovery work later at all"], correct:0, explanation:"Management enables resources and decisions; they do not perform the technical containment work." },
  { id:80354, domain:2, level:3, question:"What is a potential consequence of failing to meet a regulatory breach notification deadline?", options:["The incident is then automatically reclassified as a completely non-reportable and minor event only","The organization may face fines, penalties, or legal action for its non-compliance with the law","All of the affected data is instantly restored to its original pre-incident state without any effort","The attacker is then legally obligated to return any and all of the information that was stolen"], correct:1, explanation:"Missing deadlines risks fines and legal action; it does not undo the underlying breach itself." },
  { id:80355, domain:2, level:2, question:"When escalating an incident, what information should the handler provide to decision-makers?", options:["Only the raw packet captures with no explanation or any surrounding context provided of any kind","A firm demand that the decision-makers personally perform all of the technical remediation work","A concise summary of the incident, its impact, actions already taken, and the available options","Nothing at all, since the decision-makers should not be told about any active incidents in progress"], correct:2, explanation:"Escalation needs a clear summary with impact and options; raw data alone is unhelpful." },
  { id:80356, domain:2, level:3, question:"Which principle should guide external communications about an incident?", options:["Sharing every single internal technical detail publicly as soon as it happens to be discovered","Refusing to communicate anything at all even when disclosure is legally required by regulation","Allowing any random employee to speak directly to the media without any coordination beforehand","Providing accurate, approved information while protecting the sensitive investigative details"], correct:3, explanation:"External communication must be accurate and approved; uncoordinated disclosure is quite risky." },
  { id:80357, domain:2, level:2, question:"Why should notification procedures specify who is authorized to communicate externally?", options:["To prevent inconsistent or unauthorized disclosures that could seriously harm the organization","To ensure that only the attacker involved communicates on the organization behalf during the event","To guarantee that no external party will ever learn about any incident under any circumstances","To remove the need to comply with any breach notification regulations that might otherwise apply"], correct:0, explanation:"Authorized spokespeople prevent harmful uncoordinated disclosure; the aim is not total silence." },
  { id:80358, domain:2, level:1, question:"What is the benefit of maintaining an updated stakeholder contact list for notifications?", options:["It ensures that the stakeholders can never actually be reached at all during normal business hours","It enables rapid, reliable notification of the right people the moment that incidents occur","It fully replaces the need for any escalation matrix during the incident response effort itself","It guarantees that every reported incident is automatically downgraded to the lowest severity level"], correct:1, explanation:"Current contact lists enable rapid notification; they complement rather than replace escalation." },
  { id:80359, domain:2, level:3, question:"What is the role of escalation during the notification phase?", options:["Ensuring that no one who actually has any authority is ever informed about the incident at all","Guaranteeing that the incident is always downgraded to the very lowest available severity level","Bringing incidents to the attention of those with the authority and skills needed to respond","Preventing the technical responders from taking any action at all on the incident being handled"], correct:2, explanation:"Escalation engages the right decision-makers; it does not downgrade or block the response." },
  { id:80360, domain:2, level:2, question:"Why should breach notification obligations be understood before an incident occurs?", options:["So the organization can freely choose to ignore any and all of the applicable regulatory rules","So the attacker involved can be notified of the breach even before the regulators are informed","So the organization can conveniently avoid ever documenting the incident that it experienced later","So the organization can meet the legal timelines and requirements once a breach is confirmed"], correct:3, explanation:"Understanding obligations ensures timely compliance; it is not about ignoring the applicable rules." },
  { id:80361, domain:2, level:3, question:"What is the primary objective of the containment phase?", options:["To limit the spread and impact of the incident while preserving the evidence for later analysis","To immediately reformat every single system in the environment in order to remove all traces of it","To publicly announce the incident to outsiders before any technical action has actually been taken","To simply ignore all of the affected systems until the recovery phase can finally begin much later"], correct:0, explanation:"Containment limits spread while preserving evidence; reformatting destroys the evidence needed." },
  { id:80362, domain:2, level:2, question:"Which of the following best describes short-term containment?", options:["Rebuilding the entire network architecture completely from scratch before any isolation even occurs","Quickly isolating the affected systems to stop immediate damage without a full network redesign","Waiting several weeks to quietly observe the attacker before taking any protective action at all","Deleting all of the available backups so that the attacker cannot restore the compromised data later"], correct:1, explanation:"Short-term containment is rapid isolation; a full redesign is instead a long-term activity." },
  { id:80363, domain:2, level:1, question:"What distinguishes long-term containment from short-term containment?", options:["It is always fully completed within the very first few seconds of first detecting the given incident","It requires no changes at all to the affected systems and relies purely on ongoing user awareness","It applies more durable and sustainable measures allowing continued operation until eradication","It focuses exclusively on notifying the media about the incident that is currently still ongoing"], correct:2, explanation:"Long-term containment provides sustainable measures; short-term is the immediate stopgap only." },
  { id:80364, domain:2, level:3, question:"Why should evidence be preserved during containment rather than only after eradication?", options:["Because the collected evidence is only ever useful once the affected systems are fully rebuilt","Because preserving the evidence early somehow prevents the incident from being contained at all","Because the attackers require that the evidence be kept fully intact before they will finally stop","Because containment and eradication actions can alter or destroy volatile artifacts and evidence"], correct:3, explanation:"Actions can destroy volatile artifacts, so evidence must be preserved before those actions occur." },
  { id:80365, domain:2, level:2, question:"Which isolation strategy retains a compromised host for analysis during containment?", options:["Disconnecting it from the network or placing it on an isolated VLAN rather than powering it off","Immediately powering off the host in order to erase all of its volatile memory before any capture","Leaving the host fully connected so that the attacker simply continues their normal operations on it","Reinstalling the operating system on the host before any of its memory or disk is even acquired first"], correct:0, explanation:"Network isolation preserves volatile data; powering off erases the memory needed for analysis." },
  { id:80366, domain:2, level:3, question:"Which containment decision requires balancing evidence preservation against business continuity?", options:["Choosing the particular font that will be used in the final incident report shared with executives","Choosing whether to keep a compromised system online for monitoring or to isolate it right away","Deciding the exact alphabetical order in which the tickets will appear in the tracking system used","Selecting which specific snacks to provide the response team during the ongoing investigation work"], correct:1, explanation:"This balance is a real containment trade-off; report fonts are entirely irrelevant to it." },
  { id:80367, domain:2, level:2, question:"Why might a handler choose not to immediately block an attacker's access during containment?", options:["Because blocking any access is simply never an acceptable containment technique in any scenario at all","Because the attacker must always be given explicit permission before any action is taken against them","To observe the attacker and gather intelligence while limiting damage, per an agreed strategy","Because containment cannot even begin until the recovery phase of the incident has fully completed"], correct:2, explanation:"Controlled observation can be a deliberate strategy; blocking access is otherwise fully valid." },
  { id:80368, domain:2, level:1, question:"What is a common short-term containment technique for a malware outbreak?", options:["Rewriting the entire application codebase completely before isolating any of the infected hosts at all","Emailing the malware sample directly to all of the employees so that they can help identify it later","Increasing user privileges broadly so that the infected systems can then be cleaned a bit more easily","Disconnecting the infected hosts from the network to prevent lateral spread of the malware"], correct:3, explanation:"Isolating infected hosts stops spread; increasing privileges only worsens the situation further." },
  { id:80369, domain:2, level:3, question:"Why is documenting containment actions important?", options:["It records what was changed so that recovery and analysis can properly account for those actions","It ensures that the attacker is fully informed of every single action that the response team performs","It fully replaces the need to preserve any of the forensic evidence at all during the incident response","It allows the response team to conveniently skip the entire eradication phase of the incident afterward"], correct:0, explanation:"Documenting changes supports recovery and analysis; it is not for informing the attackers at all." },
  { id:80370, domain:2, level:2, question:"What is the goal of isolating an affected system during containment?", options:["To immediately and permanently erase the system so that no evidence can ever be recovered from it","To prevent the threat from spreading to other systems while the analysis of it still continues","To make the system fully publicly accessible so that users can simply continue working on it as usual","To grant the attacker additional elevated privileges on the isolated system for some unstated reason"], correct:1, explanation:"Isolation stops spread while preserving the system; erasing it destroys the evidence entirely." },
  { id:80371, domain:2, level:3, question:"Which factor should influence the choice of containment strategy?", options:["The particular brand of coffee that happens to be preferred by the incident response team members","The alphabetical position of the affected system hostname within the overall list of the systems","The criticality of the affected systems, the potential damage, and the evidence preservation needs","The total number of social media followers that the organization currently has across its accounts"], correct:2, explanation:"Strategy depends on criticality and evidence needs, not on any of the irrelevant preferences." },
  { id:80372, domain:2, level:2, question:"Why is it risky to power off a compromised system as a first containment step?", options:["It permanently improves the overall security posture of every other system that is also involved","It is the only method that is ever available to contain any type of security incident whatsoever","It automatically notifies all of the stakeholders that the containment effort has already succeeded in this scenario","It destroys the volatile data in memory that may well contain crucial forensic evidence for the case"], correct:3, explanation:"Powering off erases volatile memory evidence; network isolation is very often preferable instead." },
  { id:80373, domain:2, level:1, question:"Which of the following is an example of long-term containment?", options:["Applying temporary firewall rules and patches so systems operate safely until they can be rebuilt","Instantly powering off a system within the very first second right after the initial detection of it","Ignoring all of the affected systems entirely until the post-incident review has finally completed","Publicly disclosing the incident to outsiders before any technical action at all has been taken yet"], correct:0, explanation:"Long-term containment sustains safe operation until eradication; it is not an instant shutdown." },
  { id:80374, domain:2, level:3, question:"Why consider the attacker's possible reaction when planning containment?", options:["The attacker reaction is entirely irrelevant because containment always simply succeeds instantly","Aggressive containment may alert the attacker, who could destroy data or accelerate their damage","Containment plans must always be openly shared with the attacker before they are actually executed","Considering the attacker reaction is strictly prohibited at all times during any containment planning"], correct:1, explanation:"Attackers may react destructively if alerted, so containment must be planned carefully first." },
  { id:80375, domain:2, level:2, question:"What is a benefit of network segmentation as a containment measure?", options:["It ensures that every single system on the network is reachable from every other system at all times","It automatically removes all of the malware from every system in the affected network segment itself","It limits an attacker's lateral movement by restricting the traffic between the network zones","It fully eliminates the need to preserve any forensic evidence at all during the incident response"], correct:2, explanation:"Segmentation restricts lateral movement; it does not itself remove malware or the evidence needs." },
  { id:80376, domain:2, level:3, question:"Why might an incident handler use account lockout as a containment action?", options:["To ensure that the attacker gains additional elevated privileges on all of the affected systems soon","To permanently delete all of the evidence that happens to be associated with the compromised account","To notify the general public that the security incident has already been fully resolved in every way","To immediately stop an attacker from using the compromised credentials to access further systems"], correct:3, explanation:"Lockout stops credential misuse; it does not grant privileges or delete any of the evidence at all." },
  { id:80377, domain:2, level:2, question:"Which of the following supports evidence preservation while containing an incident?", options:["Capturing volatile data and imaging systems before making any disruptive containment changes","Wiping all of the affected systems immediately in order to guarantee that the threat is fully gone","Editing the log files to remove any entries that happen to seem confusing to the responders involved","Powering off all of the systems first so that the overall containment effort becomes faster and simpler"], correct:0, explanation:"Capturing data before disruptive actions preserves evidence; wiping destroys it entirely instead." },
  { id:80378, domain:2, level:1, question:"What is a risk of overly aggressive containment measures?", options:["They guarantee that no evidence at all will ever need to be preserved during the incident response","They may disrupt legitimate business operations far more than the incident itself would have done","They ensure that the attacker involved is automatically identified and then prosecuted every time","They fully remove the need for any recovery activities whatsoever at any point after the containment"], correct:1, explanation:"Aggressive containment can over-disrupt operations; it does not auto-identify the attackers involved." },
  { id:80379, domain:2, level:3, question:"Why is maintaining a chain of custody critical during evidence gathering?", options:["It allows any team member to freely modify the evidence as long as they simply log in first each time","It speeds up eradication by permitting all of the collected evidence to be discarded almost immediately","It documents who handled the evidence and when, preserving its integrity and admissibility","It fully replaces the need to create any forensic images of the affected media before analysis begins"], correct:2, explanation:"Chain of custody preserves integrity; it never permits any modification of the collected evidence." },
  { id:80380, domain:2, level:2, question:"When acquiring digital evidence, why should a forensic image be created?", options:["To permanently overwrite the original media so that it can never again be examined by anyone later","To ensure that the collected evidence is only ever readable by the attacker who first created it","To conveniently avoid the need to document the acquisition process in any real way whatsoever","To preserve the original media completely unaltered while the analysis is performed on the copy"], correct:3, explanation:"Imaging preserves the original for analysis on a copy; it does not overwrite any originals." },
  { id:80381, domain:2, level:3, question:"In what order should volatile evidence generally be collected during acquisition?", options:["From most volatile to least volatile, such as memory before disk before the archived log files","From least volatile to most volatile, starting first with the archived backups before anything else","In a completely random order since the volatility has no real effect on the evidence integrity at all","Only after the system has already been powered off in order to simplify the whole collection process"], correct:0, explanation:"Order of volatility means collecting memory first; powering off destroys the volatile data entirely." },
  { id:80382, domain:2, level:2, question:"What is the purpose of calculating and recording a cryptographic hash of acquired evidence?", options:["To encrypt the collected evidence so that only the attacker involved can decrypt and read it later","To later verify that the evidence has not been altered at all since the moment it was acquired","To compress the evidence significantly and then permanently remove all of its original metadata","To conveniently eliminate the need for any documented chain-of-custody record for the evidence"], correct:1, explanation:"Hashing verifies integrity; it neither encrypts for attackers nor replaces the custody records." },
  { id:80383, domain:2, level:1, question:"What is the purpose of using write blockers during evidence acquisition?", options:["To speed up the overall imaging process by simply skipping the verification of the resulting copy","To encrypt the original source media so that the investigators can no longer access it themselves","To prevent any accidental modification of the source media while it is actively being imaged","To automatically delete any irrelevant files from the source media before the imaging even begins"], correct:2, explanation:"Write blockers prevent source modification; they do not delete or encrypt any of the source data." },
  { id:80384, domain:2, level:3, question:"Why should evidence be stored securely with restricted access after acquisition?", options:["To allow anyone in the whole organization to freely alter the evidence whenever they need to do so","To ensure that the collected evidence is fully destroyed before the investigation has even completed","To make the collected evidence available for public download by anyone without any restriction at all","To maintain its integrity and chain of custody by preventing any unauthorized tampering with it"], correct:3, explanation:"Secure storage preserves integrity and custody; open access would badly compromise both of them." },
  { id:80385, domain:2, level:2, question:"Which of the following best supports the admissibility of digital evidence in legal proceedings?", options:["A complete, unbroken chain of custody and documented, repeatable acquisition procedures used","An acquisition that was performed by an untrained person with no accompanying documentation at all","Evidence that was collected only after the affected systems had already been rebuilt from scratch first","A single verbal description of the collected evidence with no supporting written records whatsoever"], correct:0, explanation:"Admissibility relies on custody and documented procedures; undocumented handling fails outright." },
  { id:80386, domain:2, level:3, question:"What is the significance of collecting timestamps and log data during forensics?", options:["They are entirely irrelevant because attackers apparently never leave any trace in the system logs","They help reconstruct the sequence of events and establish an accurate overall incident timeline","They should always be deleted in order to reduce the total size of the overall evidence collection","They only ever matter for the recovery phase and not for the actual investigation of the incident"], correct:1, explanation:"Timestamps and logs build the timeline; deleting them would destroy key evidence needed later." },
  { id:80387, domain:2, level:2, question:"Why is it important to acquire a memory dump from a live compromised system?", options:["Memory contents are always exactly identical to the disk contents and provide no extra value at all","Memory should never be captured at all because doing so always corrupts the entire investigation","Memory can contain running malware, encryption keys, and network connections not stored on disk","Memory acquisition conveniently removes the need to document the chain of custody for the evidence"], correct:2, explanation:"Memory holds volatile artifacts absent from disk; it is not identical to the disk contents at all." },
  { id:80388, domain:2, level:1, question:"What is the purpose of a chain-of-custody form?", options:["To provide the attacker involved with a helpful receipt for the data that was taken by the team","To fully replace the need to hash and verify the integrity of the collected evidence afterward","To authorize any investigator at all to modify the collected evidence without any record kept of it","To record every person who handled the evidence and each transfer or access event involving it"], correct:3, explanation:"The form logs handling and transfers; it does not replace the integrity verification of evidence." },
  { id:80389, domain:2, level:3, question:"Which practice helps ensure evidence integrity from collection through analysis?", options:["Working from verified forensic copies while keeping the originals securely preserved and untouched","Performing all of the analysis work directly on the original evidence media itself to save some time","Allowing multiple people to edit the collected evidence simultaneously without any logging at all","Discarding all of the calculated hash values immediately once the evidence has first been collected"], correct:0, explanation:"Analysis on verified copies preserves originals; working on originals risks accidental alteration." },
  { id:80390, domain:2, level:2, question:"Why should original evidence media be handled as little as possible?", options:["To ensure that the media degrades as quickly as possible and then becomes completely unusable soon","To minimize the risk of accidental alteration that could seriously compromise its overall integrity","To allow the collected evidence to be shared publicly by anyone without any restrictions applied to it","To make it much easier to blame the original reporter for the security incident having occurred at all"], correct:1, explanation:"Minimal handling protects integrity; frequent handling only risks accidental alteration of it." },
  { id:80391, domain:2, level:3, question:"What is the value of documenting the tools and versions used during forensic acquisition?", options:["It provides the attacker involved with a complete list of all of the investigator capabilities used","It fully removes the need to maintain any chain of custody for the collected evidence afterward","It supports reproducibility and demonstrates that sound and defensible methods were actually used","It ensures that the collected evidence can be quietly altered without ever leaving any trace at all"], correct:2, explanation:"Documenting tools supports reproducibility; it does not replace the chain of custody at all." },
  { id:80392, domain:2, level:2, question:"What is the main objective of the eradication phase?", options:["To restore all of the systems to production before the malicious artifacts have even been removed","To notify the regulators that the incident has already been completely closed out and then archived","To collect the very first forensic image of the affected systems for the later analysis of the case","To remove the cause of the incident and all related malicious artifacts from the environment"], correct:3, explanation:"Eradication removes the cause and artifacts; restoring before removal reintroduces the risk." },
  { id:80393, domain:2, level:1, question:"Why is root cause analysis an essential part of eradication?", options:["It identifies the underlying vulnerability so that it can be fixed to prevent any recurrence later","It assigns the personal blame to whichever user happened to first report the given incident overall","It guarantees that no monitoring at all will be needed during the recovery phase of the incident later","It allows the team to conveniently skip validating that the threat was actually fully removed first"], correct:0, explanation:"Root cause analysis prevents recurrence; it is not about assigning blame or skipping validation." },
  { id:80394, domain:2, level:3, question:"Which eradication action addresses a vulnerability that allowed the initial compromise?", options:["Restoring the affected system from an older backup that still happens to contain the very same flaw","Applying the appropriate patches or configuration hardening to close the exploited weakness","Ignoring the vulnerability entirely because the containment step had already stopped its spread anyway","Disabling all of the logging so that the vulnerability simply no longer generates any alerts at all"], correct:1, explanation:"Patching closes the weakness; restoring a flawed backup leaves the same exposure fully in place." },
  { id:80395, domain:2, level:2, question:"After removing malware, why verify that no backdoors or persistence remain?", options:["Because malware removal automatically eliminates every single attacker foothold every single time","Because verifying for persistence is only ever necessary during the preparation phase, not later on","Because attackers often install persistence mechanisms to regain access after the initial cleanup","Because backdoors simply cannot exist once the primary piece of malware has already been deleted"], correct:2, explanation:"Attackers use persistence, so verification is essential; removal alone is not sufficient at all." },
  { id:80396, domain:2, level:3, question:"Which of the following is part of thorough eradication of a compromised account?", options:["Leaving the compromised credentials fully active in order to observe the attacker indefinitely later","Deleting the account logs entirely so that the compromise itself can no longer be traced afterward","Ignoring the account because the password policies will eventually force a change on their own anyway","Resetting the credentials, revoking active sessions, and reviewing for any unauthorized changes"], correct:3, explanation:"Full eradication resets credentials and revokes access; leaving them active is highly unsafe." },
  { id:80397, domain:2, level:2, question:"Why should eradication address all affected systems, not just the one first detected?", options:["Because attackers frequently move laterally and compromise multiple systems in an environment","Because only the very first system that was detected can ever really be affected in any incident at all","Because addressing multiple systems at once is strictly prohibited during the eradication phase itself","Because lateral movement is simply a myth that does not actually occur in any real-world incidents"], correct:0, explanation:"Lateral movement means multiple systems may be compromised; the scope must be complete." },
  { id:80398, domain:2, level:1, question:"What is a sign that eradication was incomplete?", options:["The affected systems run noticeably faster than they did before the security incident even occurred","Malicious activity or indicators of compromise reappear again after the initial cleanup efforts","Users report that their account passwords were successfully reset by the response team as expected","The final incident report was fully completed and then shared with all of the relevant stakeholders"], correct:1, explanation:"Reappearing indicators signal incomplete eradication; faster systems do not indicate this." },
  { id:80399, domain:2, level:3, question:"Why identify all indicators of compromise before eradication?", options:["To provide the attacker involved with a complete and detailed list of exactly what was detected","To help justify conveniently skipping the root cause analysis during the eradication phase later on","To ensure that every instance of the threat can be located and then removed across the environment","To ensure that only the very first affected system is ever actually cleaned during the whole response"], correct:2, explanation:"Identifying all IOCs enables complete removal; sharing them with attackers would be absurd." },
  { id:80400, domain:2, level:2, question:"Why is coordinating eradication across all affected systems important?", options:["Eradicating one single system automatically cleans every other system in the network all at once","Coordinating the eradication is entirely unnecessary because attackers only ever use one system total","Eradication should only ever be performed after the systems have already returned to production use","Partial eradication can leave footholds that let the attacker re-establish the entire compromise"], correct:3, explanation:"Uncoordinated eradication leaves footholds; cleaning one system does not clean the others too." },
  { id:80401, domain:2, level:3, question:"What is a valid eradication step after a web application compromise?", options:["Removing the malicious files, closing the exploited vulnerability, and then validating the fix","Restoring the application from an old backup that still contains the very same known vulnerability","Leaving the malicious web shell fully in place in order to monitor the future traffic to the site","Ignoring the vulnerability entirely since the firewall will surely block all future attacks anyway"], correct:0, explanation:"Proper eradication removes artifacts and closes the flaw; a flawed backup re-exposes the system." },
  { id:80402, domain:2, level:2, question:"Why is validating eradication before recovery important?", options:["To ensure that the affected systems are restored while the underlying threat is still present on them","To confirm the threat and its artifacts are fully removed before systems return to service again","To help justify conveniently skipping any monitoring of the systems after the recovery has completed","To provide the attacker involved with a clear confirmation that the cleanup effort has now finished"], correct:1, explanation:"Validating eradication first prevents restoring a system that is still actively compromised." },
  { id:80403, domain:2, level:1, question:"What is a common root cause category identified during eradication?", options:["The particular brand of the computer monitor that was being used by the affected end user at the time","The total number of employees who happened to be away on vacation at the exact time of the incident","An unpatched vulnerability, a misconfiguration, or a compromised credential that enabled entry","The specific color of the network cables that were connecting the affected servers in the data center"], correct:2, explanation:"Root causes are technical entry points like unpatched flaws, not any of the superficial factors." },
  { id:80404, domain:2, level:3, question:"What is the primary goal of the recovery phase?", options:["To immediately delete all of the evidence that was carefully collected during the earlier investigation","To reconnect the compromised systems before confirming that the underlying threat was fully removed","To permanently keep all of the affected systems offline regardless of any of the real business needs","To restore affected systems to normal operation and validate they are clean and fully functional"], correct:3, explanation:"Recovery restores and validates systems; reconnecting before verification risks reinfection." },
  { id:80405, domain:2, level:2, question:"Why is validation important before returning a recovered system to production?", options:["To confirm the system is free of malicious artifacts and is functioning fully as it is expected to","To ensure that the attacker involved has been given advance notice of the upcoming restoration effort","To conveniently avoid the need for any monitoring at all once the system is finally back online again","To guarantee that no backups whatsoever will ever be required for that particular system again later"], correct:0, explanation:"Validation confirms the system is clean and working; it does not eliminate the monitoring needs." },
  { id:80406, domain:2, level:3, question:"Why should enhanced monitoring be applied to systems immediately after recovery?", options:["To deliberately slow down the recovered systems so that users are discouraged from using them at all","To detect any signs of reinfection or attacker return before normal operations fully resume again","To fully replace the need to validate that the recovered systems were actually properly cleaned first","To ensure that all of the previously collected evidence is then automatically deleted right afterward"], correct:1, explanation:"Enhanced monitoring catches reinfection; it complements rather than replaces the validation step." },
  { id:80407, domain:2, level:2, question:"What is a key consideration when deciding the timing of system restoration during recovery?", options:["Restoring all of the systems as fast as is possible even if the underlying threat is still present on them","Waiting all the way until the next annual audit before restoring any of the affected systems at all","Ensuring eradication is complete and the threat removed before systems return to active service","Restoring the systems only after first deleting all of the existing backups of the affected data"], correct:2, explanation:"Restoration should follow complete eradication; premature restoration only risks reinfection." },
  { id:80408, domain:2, level:1, question:"Why might a phased approach be used when restoring systems during recovery?", options:["To ensure that all of the systems fail simultaneously so that the troubleshooting becomes simpler","To conveniently avoid ever restoring any of the less critical business systems at any point in time","To guarantee that all monitoring becomes unnecessary the moment the very first system returns online","To restore the critical services first and monitor for stability before bringing back all the rest"], correct:3, explanation:"Phased recovery prioritizes and monitors; it does not skip any monitoring or restoration steps." },
  { id:80409, domain:2, level:3, question:"What should be validated after restoring data from backups during recovery?", options:["That the restored data is complete, uncorrupted, and free of any malicious artifacts within it","That the backup media used is destroyed immediately right after the restore operation completes","That the restored data is then made fully publicly accessible to all of the external users at once","That the restore process skipped any and all integrity checks in order to save processing time"], correct:0, explanation:"Restored data must be verified clean and complete; destroying the backups is inappropriate." },
  { id:80410, domain:2, level:2, question:"Why is it important to define recovery success criteria in advance?", options:["So the team can freely restore the systems without ever validating that they are actually clean first","So the team can objectively confirm systems are clean and operational before the incident is closed","So the entire recovery phase can be conveniently skipped for all of the most critical systems involved","So the attacker involved can independently verify that the recovery was performed correctly by staff"], correct:1, explanation:"Success criteria enable objective validation; skipping validation only risks a reinfection later." },
  { id:80411, domain:2, level:3, question:"What should be done if monitoring after recovery reveals signs of continued compromise?", options:["Ignore the observed signs entirely because the recovery phase has already been declared complete","Immediately delete all of the monitoring data collected in order to keep the incident record clean","Re-engage the containment and eradication steps, since the threat was clearly not fully removed","Assume that the monitoring tools themselves are simply faulty and then disable them all permanently"], correct:2, explanation:"Continued compromise means returning to containment and eradication, not ignoring the signs." },
  { id:80412, domain:2, level:2, question:"Why should systems be restored to a known-good state during recovery?", options:["To ensure that the restored environment somehow still contains the very same original malware on it","To guarantee that all of the restored systems will simply fail again in exactly the same manner later","To conveniently avoid the need to validate any of the restored systems at all before putting them to use","To ensure the restored environment is free of the compromise and is reliable for operations again"], correct:3, explanation:"A known-good state ensures a clean, reliable environment; validation is still required afterward." },
  { id:80413, domain:2, level:1, question:"What is a benefit of gradually reconnecting recovered systems to the network?", options:["It allows the team to monitor for any problems and reinfection before the full restoration completes","It ensures that all of the recovered systems become compromised again simultaneously at the same time","It fully removes the need to validate that any of the recovered systems are actually clean beforehand","It guarantees that the attacker involved cannot observe the ongoing recovery process in any way at all"], correct:0, explanation:"Gradual reconnection allows monitoring for issues; it does not skip any of the validation steps." },
  { id:80414, domain:2, level:3, question:"Why is validation important after restoring a critical business system during recovery?", options:["To ensure that the restored critical system is left completely unmonitored right after it comes online","To confirm the system operates correctly and securely before users depend on it for their work","To guarantee that the restored system will never once require any future patching or maintenance work","To provide the attacker with confirmation that the critical system has been successfully restored again"], correct:1, explanation:"Validation confirms correct, secure operation; leaving a system unmonitored after restore is risky." },
  { id:80415, domain:2, level:2, question:"What is the main purpose of post-incident activities such as a lessons-learned review?", options:["To assign public blame to specific individuals so that they can then be disciplined right away","To ensure that the exact same incident response steps are never once changed again going forward","To identify improvements to the processes, controls, and readiness for handling future incidents","To delete all of the documentation so that the handled incident can never be referenced again later"], correct:2, explanation:"Lessons learned drive improvement; the goal is not assigning blame or discarding the records." },
  { id:80416, domain:2, level:3, question:"What should the final incident report ideally include?", options:["Only the names of the employees who should be publicly blamed for the incident having occurred at all","A firm guarantee that no similar incident can ever possibly happen again at any point in the future","Only marketing language intended to reassure the customers without any of the real technical facts","A timeline, the actions taken, the impact, the root cause, and recommendations for improvement"], correct:3, explanation:"A final report documents the full picture and recommendations, not blame or empty promises." },
  { id:80417, domain:2, level:2, question:"When should a lessons-learned meeting ideally be conducted?", options:["Shortly after the incident is resolved, while the important details are still fresh in everyone memory","Several full years later once all of the staff who were originally involved have left the organization","Before the incident has even been detected so that essentially no relevant facts are yet available","Only if the incident happened to cause a complete and total loss of every bit of the organization data"], correct:0, explanation:"Prompt reviews capture fresh details; delaying for years loses the valuable context entirely." },
  { id:80418, domain:2, level:1, question:"How do post-incident lessons learned improve organizational security posture?", options:["They ensure that the incident response plan is permanently frozen and then never updated again ever","They feed process, control, and training improvements back into the ongoing preparation phase","They are archived carefully and then deliberately never reviewed again by anyone in the organization","They focus solely on identifying exactly which single employee to terminate after the incident ends"], correct:1, explanation:"Lessons learned drive continuous improvement, closing the loop back to the preparation phase." },
  { id:80419, domain:2, level:3, question:"What metric might a post-incident review use to evaluate response effectiveness?", options:["The total number of completely unrelated marketing campaigns launched during that same quarter","The average daily commute time of each of the incident response team members to the main office","Mean time to detect and mean time to respond compared against the previously defined targets","The total number of coffee cups that were consumed by the team during the entire investigation"], correct:2, explanation:"MTTD and MTTR measure effectiveness; the unrelated metrics do not evaluate response at all." },
  { id:80420, domain:2, level:2, question:"Why should the incident response plan be updated after significant incidents?", options:["To ensure that the response plan can never once be changed again under any circumstances whatsoever","To remove all of the existing documentation so that future teams start with absolutely no guidance","To guarantee that no future incident of any kind will ever require any response effort at all again","To incorporate the lessons learned and to address any gaps that were identified during the response"], correct:3, explanation:"Updating the plan captures lessons; freezing or deleting the guidance only harms future readiness." },
  { id:80421, domain:2, level:3, question:"What is the value of preserving the final incident report for future reference?", options:["It provides institutional knowledge for training, audits, and handling any similar incidents later","It allows the organization to formally bill the attacker for the full cost of the incident response","It fully replaces the need for any monitoring of the recovered systems at any point going forward","It ensures that the same incident will always be handled identically without any adaptation at all"], correct:0, explanation:"Reports build institutional knowledge; they do not bill attackers or freeze the response process." },
  { id:80422, domain:2, level:2, question:"Who should typically participate in a lessons-learned review?", options:["Only the single most junior analyst, so that the more senior staff are not inconvenienced at all","Everyone who was involved in the response, plus the relevant stakeholders and the decision-makers","Only the attacker involved, who supposedly has the best view of exactly what went wrong overall","No one at all, since the lessons-learned reviews provide essentially no organizational value ever"], correct:1, explanation:"Broad participation captures the full perspective; excluding responders only limits the learning." },
  { id:80423, domain:2, level:1, question:"What is a key reason to quantify the impact of an incident during post-incident activities?", options:["It ensures that the exact same incident will then occur again in precisely the same way as before","It allows the organization to conveniently avoid any and all future security spending going forward","It informs risk decisions, helps justify security investments, and supports later reporting needs","It guarantees that the regulators will never once require any breach notification for the incident"], correct:2, explanation:"Quantifying impact informs risk and investment decisions; it does not prevent any recurrence." },
  { id:80424, domain:2, level:3, question:"What should recommendations in a final incident report focus on?", options:["Assigning personal blame to specific individual employees for the security incident occurring at all","Ensuring that the response process is never once modified in any way at all going forward in future","Reassuring the readers with only vague statements that contain no actionable content whatsoever","Concrete improvements to the controls, processes, and readiness needed to reduce future risk"], correct:3, explanation:"Recommendations should be concrete improvements, not assigned blame or vague reassurance." },
  { id:80425, domain:2, level:2, question:"Why should incident metrics be tracked over time as a post-incident activity?", options:["Trends help identify any recurring issues and measure whether the overall response is improving","The metrics ensure that the very same incident will then happen again at completely regular intervals","Tracking the metrics conveniently removes the need to ever update the incident response plan again","The metrics are only ever really useful to the attacker who is analyzing the organization defenses"], correct:0, explanation:"Trends reveal recurring issues and improvement; they do not cause any of the incidents themselves." },
  { id:80426, domain:2, level:3, question:"What is the final step that formally concludes an incident?", options:["Powering off all of the systems across the entire organization just to be as safe as possible for now","Documenting closure with a final report once recovery and the lessons learned are both complete","Notifying the attacker involved that the incident record has now finally been closed out by the team","Deleting all of the evidence and every record that is related to the incident entirely and permanently"], correct:1, explanation:"Closure is documented after recovery and lessons learned; the records are retained, not deleted." },
  { id:80427, domain:2, level:2, question:"Why is it important to review whether the incident response plan was effective?", options:["To confirm that the plan should from now on never be modified under any circumstances whatsoever","To assign the personal blame to the author of the plan for any shortcomings that were found in it","To identify any gaps and refine the plan so that future incidents are handled more effectively","To help justify discarding the response plan entirely and then starting over completely each time"], correct:2, explanation:"Reviewing effectiveness refines the plan; the goal is improvement, not assigning any blame." },
  { id:80428, domain:2, level:1, question:"Which responsibility falls to the incident handler across most phases of IH&R?", options:["Personally approving the entire annual marketing budget for the whole organization every single year","Physically repairing all of the failed hardware components located within the main data center","Setting the retail pricing for all of the various products that the company happens to sell to customers","Coordinating the response activities and accurately documenting the actions and findings throughout"], correct:3, explanation:"Handlers coordinate and document across phases; unrelated business tasks are out of their scope." },
  { id:80429, domain:2, level:3, question:"During triage, what is a primary responsibility of the incident handler?", options:["Validating the incident and assigning it an appropriate category, priority, and severity level","Publicly announcing the incident to all of the customers before any validation of it has occurred yet","Deleting all of the collected evidence in order to speed up the closure of the incident ticket sooner","Rebuilding all of the affected systems immediately before determining the actual scope of the incident"], correct:0, explanation:"The handler validates and classifies during triage; premature announcements are entirely wrong." },
  { id:80430, domain:2, level:2, question:"What is the incident handler's role regarding communication during an incident?", options:["Withholding absolutely all information from every single stakeholder until the incident is fully closed","Providing timely, accurate updates to the stakeholders through the properly defined channels","Communicating the incident details directly to the attacker in order to negotiate some kind of terms","Posting all of the technical details publicly before the management team has even been informed at all"], correct:1, explanation:"Handlers keep stakeholders informed via proper channels; withholding all info would be harmful." },
  { id:80431, domain:2, level:3, question:"In which phase does the incident handler primarily focus on removing the root cause?", options:["The preparation phase, which naturally occurs entirely before any incident has even been detected yet","The notification phase, which instead focuses mainly on informing the various relevant stakeholders","The eradication phase, where the underlying cause and all related artifacts are finally eliminated","The recording phase, which simply logs the very initial report of the incident when it first comes in"], correct:2, explanation:"Root cause removal happens in eradication; the preparation phase precedes any incident entirely." },
  { id:80432, domain:2, level:2, question:"What is the incident handler's responsibility regarding evidence during containment?", options:["Destroying all of the collected evidence quickly so that the incident can then be closed much faster","Handing all of the collected evidence to the attacker involved for safekeeping during the response","Ignoring the evidence entirely because it is supposedly only relevant during the later recovery phase","Preserving the evidence integrity while taking the actions needed to limit the incident impact"], correct:3, explanation:"Handlers preserve evidence even while containing; destroying it would undermine the whole case." },
  { id:80433, domain:2, level:1, question:"Across the IH&R process, why must the incident handler document actions in real time?", options:["Real-time records preserve an accurate account for the analysis, reporting, and any legal needs","Real-time documentation is only ever useful for deliberately slowing down the whole response effort","Documentation should only ever be created after the attacker involved has finally been arrested first","The records should always be written entirely from memory several weeks after the incident concludes"], correct:0, explanation:"Real-time records are accurate and defensible; memory-based records are unreliable and weak." },
  { id:80434, domain:2, level:3, question:"What is the incident handler's role during the notification phase?", options:["Personally deciding the entire public relations strategy of the whole organization all by themselves","Ensuring the right stakeholders are informed and that escalation occurs per the defined procedure","Refusing to inform anyone at all about the incident until it has been completely closed out first","Communicating exclusively with the attacker involved in order to resolve the incident on their own"], correct:1, explanation:"Handlers ensure proper stakeholder notification and escalation, not any solo PR strategy work." },
  { id:80435, domain:2, level:2, question:"What is the incident handler's key role during the recovery phase?", options:["Deciding the organization entire long-term product roadmap for the upcoming year during recovery","Communicating directly with the attacker involved in order to negotiate some kind of settlement deal","Coordinating the restoration and validating that systems are clean and fully operational again","Deleting all of the collected evidence just to make the overall recovery process go a little faster"], correct:2, explanation:"Handlers coordinate restoration and validation in recovery; unrelated tasks are out of scope." },
  { id:80436, domain:2, level:3, question:"During the preparation phase, what is a core responsibility of the incident handler?", options:["Personally approving the organization entire marketing budget for the quarter during preparation","Responding directly to incidents that have not actually been detected or even reported yet at all","Deleting all of the historical incident records just to reduce the clutter in the tracking system","Helping develop the plans, tools, and training so that the whole team is ready to respond well"], correct:3, explanation:"Handlers build readiness in preparation; they cannot respond to undetected or unreported incidents." },
  { id:80437, domain:2, level:2, question:"What is the incident handler's responsibility regarding lessons learned?", options:["Facilitating the review and ensuring the identified improvements are documented and then tracked","Ensuring that no improvements at all are ever actually made to the response process going forward","Assigning the personal blame to specific individuals rather than working to improve the process itself","Discarding all of the review findings so that they can never influence any future response efforts"], correct:0, explanation:"Handlers drive improvement tracking; the goal is process improvement rather than assigning blame." },
  { id:80438, domain:2, level:1, question:"Why must the incident handler maintain objectivity throughout the IH&R process?", options:["To ensure that the handler always simply agrees with whatever demands the attacker happens to make","To ensure decisions are based on the evidence and the facts rather than assumptions or any bias","To guarantee that no documentation of any kind is ever produced during the entire incident response","To ensure that every single incident is closed out as a false positive by default from the beginning"], correct:1, explanation:"Objectivity keeps decisions evidence-based; bias or assumptions inevitably lead to costly errors." },
  { id:80439, domain:2, level:3, question:"What is the incident handler's role in coordinating with external parties during an incident?", options:["Independently signing binding legal contracts with any external party without any prior approval at all","Refusing all external assistance even when the incident clearly exceeds the internal team capability","Engaging law enforcement, vendors, or forensic experts as needed while following defined procedures","Sharing full unredacted evidence with any external party who happens to ask for it during the response"], correct:2, explanation:"Handlers engage external parties per procedure; they do not sign contracts or overshare freely." },
  { id:80440, domain:2, level:2, question:"Why is establishing an incident response team charter valuable during preparation?", options:["It ensures that the response team can never be held accountable for any of its actions taken later","It fully replaces the need for any written incident response procedures across the whole organization","It guarantees that the team will never actually need to escalate any incident to management at all","It formally grants the team the authority and mandate it needs to act during security incidents"], correct:3, explanation:"A charter grants authority and mandate; it does not remove accountability or the need for procedures." },
  { id:80441, domain:2, level:3, question:"What is the value of maintaining out-of-band communication channels for incident response?", options:["They allow the team to coordinate even if the primary systems or networks are themselves compromised","They ensure that all incident communications are always broadcast publicly to every single employee in this scenario","They guarantee that the attacker involved cannot ever intercept normal business email at any time","They fully remove the need to maintain any stakeholder contact list during the incident response"], correct:0, explanation:"Out-of-band channels keep coordination possible when primary systems are compromised." },
  { id:80442, domain:2, level:2, question:"Why is defining data classification useful for incident handling preparation?", options:["It ensures that all data in the organization is treated as equally sensitive during every incident","It helps responders quickly assess impact and notification needs based on the sensitivity of data","It removes the need to ever assess the business impact of an incident during the triage phase later","It guarantees that no data of any classification can ever be exposed during a security incident at all"], correct:1, explanation:"Data classification speeds impact and notification assessment; it does not make all data equal." },
  { id:80443, domain:2, level:1, question:"What is the benefit of pre-defined incident response runbooks for common attack types?", options:["They ensure that every incident is handled identically regardless of its type or its real impact","They fully remove the need for any human judgment during the handling of a security incident at all","They give responders step-by-step guidance so that consistent action can be taken under pressure","They guarantee that any incident matching a runbook can be completely ignored by the response team"], correct:2, explanation:"Runbooks give consistent guidance; they do not remove judgment or make incidents ignorable." },
  { id:80444, domain:2, level:3, question:"During recording, why should the affected asset owner be identified early?", options:["So the owner can be publicly blamed if the incident on their asset turns out to be significant","So the owner is prevented from ever learning any details about the incident affecting their asset","So the response team can transfer full responsibility for the incident entirely onto that asset owner","So the owner can provide context, authorize actions, and support the response on their systems"], correct:3, explanation:"Early owner identification provides context and authorization; it is not about assigning blame." },
  { id:80445, domain:2, level:2, question:"What is a benefit of linking related incident records together during recording?", options:["It helps reveal patterns or a larger campaign that separate individual records might otherwise hide","It ensures that all of the linked incidents are automatically closed at exactly the same moment","It guarantees that each of the linked incidents is a confirmed false positive that can be dismissed","It removes the need to triage or prioritize any of the individual incidents that have been linked"], correct:0, explanation:"Linking records reveals patterns and campaigns; it does not auto-close or dismiss incidents." },
  { id:80446, domain:2, level:3, question:"Why should the method of incident detection be recorded during the recording step?", options:["It ensures that the incident is always escalated directly to the executives regardless of its impact","It informs the reliability of the report and helps improve detection tuning and coverage later","It guarantees that the reported incident is a genuine true positive requiring no further validation","It removes the need to categorize or assess the severity of the incident during the triage phase"], correct:1, explanation:"Recording the detection method aids reliability assessment and detection tuning later on." },
  { id:80447, domain:2, level:2, question:"During triage, how should an incident affecting regulated data typically be handled?", options:["It should be closed immediately since regulated data incidents are always minor by their nature","It should be ignored until the annual compliance audit reviews all of the incidents from the year","It should be prioritized highly and flagged for the potential notification obligations that apply","It should be handled identically to any other incident with no regard for the data involved at all"], correct:2, explanation:"Regulated data raises priority and notification needs; it should not be treated as always minor." },
  { id:80448, domain:2, level:1, question:"What is the purpose of assigning an incident to a specific handler during triage?", options:["It ensures that no single person is ever responsible for the outcome of the incident being handled","It guarantees that the incident will be resolved within a fixed time regardless of its complexity","It removes the need to document any of the actions that are taken during the incident response","It establishes clear ownership so that the response is coordinated and accountable throughout"], correct:3, explanation:"Clear ownership ensures coordinated, accountable response; it does not remove documentation needs." },
  { id:80449, domain:2, level:3, question:"Why is understanding the attack vector useful during triage?", options:["It helps scope the incident and guides the containment and eradication strategy that will be used","It ensures that the incident is always closed as a false positive once the vector is identified","It guarantees that no other systems in the environment could possibly have been affected as well","It removes the need to assess the business impact of the incident during the rest of the triage step"], correct:0, explanation:"Knowing the attack vector helps scope the incident and guide containment and eradication choices." },
  { id:80450, domain:2, level:2, question:"During notification, why should the sensitivity of shared information be considered?", options:["All investigative details should always be shared with everyone to ensure full transparency at all","Oversharing investigative details can tip off attackers or cause reputational and legal harm","The sensitivity of information never matters because attackers already know all of the details anyway","Considering sensitivity simply slows the response and provides no real value to the organization"], correct:1, explanation:"Managing information sensitivity avoids tipping off attackers and reputational or legal harm." },
  { id:80451, domain:2, level:3, question:"Why is documenting all notifications made during an incident important?", options:["It ensures that the notified parties can never take any action based on what they were told at all","It guarantees that no further notifications will ever be required at any later point in the incident","It provides a record proving that required parties were informed within the applicable timelines","It removes the need to maintain any escalation matrix or stakeholder contact list going forward"], correct:2, explanation:"Notification records prove compliance with informing required parties within the timelines." },
  { id:80452, domain:2, level:2, question:"When should executive leadership typically be notified during an incident?", options:["For every single minor event regardless of its impact so that leaders review each one individually","Only after the incident has been fully closed and the final report has already been archived away","Never, because executives should be kept entirely unaware of any security incidents at all times","When the incident is significant enough to affect business operations, reputation, or compliance"], correct:3, explanation:"Leaders are notified for significant impact; trivial events and post-closure-only both miss the mark." },
  { id:80453, domain:2, level:1, question:"Why is a customer notification sometimes required following an incident?", options:["Affected customers may need to take protective steps and laws may mandate their notification","Customers must always be notified of every internal event even when they are not affected at all","Customer notification is never required under any circumstances following a security incident","Notifying customers removes the organization obligation to notify any regulators about the breach"], correct:0, explanation:"Customer notification enables protective steps and may be legally mandated for affected parties." },
  { id:80454, domain:2, level:3, question:"Why should containment strategy account for the affected system's role in operations?", options:["The operational role of a system has no bearing at all on how it should be contained during response","Containing a critical production system needs care to avoid unacceptable business disruption","Critical systems should always simply be powered off instantly regardless of any business impact","The operational role only matters during recovery and never during the containment of an incident"], correct:1, explanation:"System role guides containment to balance security against unacceptable business disruption." },
  { id:80455, domain:2, level:2, question:"What is a benefit of using pre-approved network isolation procedures during containment?", options:["Pre-approved procedures ensure that no compromised system is ever actually isolated during response","They guarantee that the isolation itself will never disrupt any legitimate business operations at all","Responders can isolate compromised systems rapidly without waiting for slow ad-hoc approvals","They remove the need to document which systems were isolated during the incident response effort"], correct:2, explanation:"Pre-approved isolation enables rapid action; it still requires documentation of what was isolated." },
  { id:80456, domain:2, level:3, question:"Why might disabling a compromised service be preferable to fully shutting down a server?", options:["It always erases more volatile evidence than a full shutdown would ever manage to erase at all","It guarantees that the attacker involved will regain their access to the server almost immediately","It removes the need to preserve any evidence from the affected server during the incident response","It can contain the threat while keeping other legitimate services on the same server available"], correct:3, explanation:"Disabling a service contains the threat while preserving other services and volatile evidence." },
  { id:80457, domain:2, level:2, question:"What is a risk of failing to identify the full scope before containment?", options:["Some compromised systems may be missed, allowing the attacker to persist elsewhere in the network","Containment will always succeed completely even without knowing the full scope of the incident","The incident will automatically be resolved without any further action once containment begins","Failing to scope the incident always improves the speed of the overall containment effort undertaken"], correct:0, explanation:"Incomplete scoping can miss compromised systems, letting the attacker persist elsewhere." },
  { id:80458, domain:2, level:1, question:"Why should a handler avoid using the compromised system's own tools during forensics?", options:["The system's own tools are always faster and more trustworthy than any external forensic tools","The system's tools may be tampered with by the attacker and could return unreliable results","Using the system's tools guarantees a fully documented and defensible chain of custody every time","The system's tools automatically preserve all of the volatile evidence without any effort needed"], correct:1, explanation:"Compromised systems may have tampered tools; trusted external tools give reliable results." },
  { id:80459, domain:2, level:3, question:"What is the purpose of maintaining an evidence log during an investigation?", options:["It provides the attacker involved with a detailed inventory of exactly what evidence was collected","It fully replaces the need to create any forensic images of the collected evidence media afterward","It records each item collected, its source, and its handling to support integrity and custody","It authorizes any investigator to freely modify the collected evidence as long as they log it first"], correct:2, explanation:"An evidence log records items, sources, and handling to support integrity and chain of custody." },
  { id:80460, domain:2, level:2, question:"Why is it important to acquire evidence before performing containment when feasible?", options:["Evidence acquired after containment is always more complete than evidence acquired beforehand is","Acquiring evidence first guarantees that the incident cannot spread any further during the response","Containment never has any effect at all on the volatile evidence present on the affected systems","Containment actions may overwrite or destroy volatile evidence needed for the later investigation"], correct:3, explanation:"Containment can destroy volatile evidence, so acquiring it first when feasible preserves it." },
  { id:80461, domain:2, level:3, question:"What is the significance of the least-volatile evidence such as archived backups?", options:["It persists longer and can be collected after the more fragile volatile data has been secured first","It is always the very first evidence that must be collected before anything else in every case","It has no forensic value at all and should therefore simply be ignored during the investigation in this scenario","It must be deleted immediately to prevent it from interfering with the volatile data collection"], correct:0, explanation:"Least-volatile evidence persists and is collected after fragile volatile data is secured first." },
  { id:80462, domain:2, level:2, question:"Why should investigators avoid altering timestamps on evidence files?", options:["Altering timestamps always makes the resulting incident timeline more accurate and more reliable","Altered timestamps can undermine the timeline and the integrity of the evidence in proceedings","Timestamps on evidence files have no bearing at all on the investigation or any later proceedings","Investigators are encouraged to update timestamps so that the evidence appears more recent overall"], correct:1, explanation:"Altered timestamps undermine the timeline and evidence integrity; they must be preserved." },
  { id:80463, domain:2, level:1, question:"What is a key eradication consideration for a compromised service account?", options:["Leaving the account credentials unchanged so that dependent services are not disrupted at all","Deleting the account entirely without checking any of the services that actually depend on it","Rotating its credentials and reviewing every system and service that relied upon that account","Ignoring the account because service accounts cannot realistically be compromised by attackers"], correct:2, explanation:"Rotating credentials and reviewing dependent systems is needed; leaving them unchanged is unsafe." },
  { id:80464, domain:2, level:3, question:"Why is testing patches before deploying them during eradication important?", options:["Patches never need any testing because they always apply cleanly to every system without issue","Testing patches guarantees that the exploited vulnerability will remain open after they are applied","Deploying patches without testing is always the fastest and safest option during any eradication","Untested patches may break critical systems, so validation reduces the risk of new disruptions"], correct:3, explanation:"Testing patches first reduces the risk that they break critical systems during eradication." },
  { id:80465, domain:2, level:2, question:"What should a handler do if eradication cannot fully remove a threat immediately?", options:["Maintain robust containment and monitoring until complete eradication can be safely achieved","Return all of the affected systems to production right away despite the threat still being present","Declare the incident closed and stop all further work since eradication was not fully successful","Delete all of the collected evidence so that the incomplete eradication is not visible to auditors"], correct:0, explanation:"If eradication is incomplete, sustained containment and monitoring bridge the gap until it is done." },
  { id:80466, domain:2, level:3, question:"Why is confirming the elimination of persistence mechanisms part of eradication?", options:["Persistence mechanisms are automatically removed whenever the primary malware file is deleted","Persistence such as scheduled tasks or startup entries can silently restore the attacker's access","Persistence has no relevance to eradication and only ever matters during the preparation phase","Confirming persistence removal is only necessary if the attacker specifically requests that it be done"], correct:1, explanation:"Persistence can silently restore access, so its removal must be confirmed during eradication." },
  { id:80467, domain:2, level:2, question:"What is a valid eradication measure after credential theft is confirmed?", options:["Leaving the stolen credentials active so that the attacker behavior can be observed indefinitely","Deleting the authentication logs so that the credential theft can no longer be traced by anyone","Forcing password resets and reviewing accounts for any unauthorized privilege escalation performed","Ignoring the theft because expiring passwords will eventually replace the stolen credentials anyway"], correct:2, explanation:"Password resets and privilege review are needed; leaving stolen credentials active is unsafe." },
  { id:80468, domain:2, level:1, question:"Why should recovery include verifying that security controls are functioning?", options:["Security controls never require any verification because they always function perfectly at all times","Verifying controls simply delays the recovery and adds no real value to the overall response effort","Controls only need to be verified during the preparation phase and never once during any recovery","Controls may have been disabled or bypassed during the incident and must be confirmed operational"], correct:3, explanation:"Controls may have been disabled during the incident, so recovery must confirm they work again." },
  { id:80469, domain:2, level:3, question:"What is the benefit of documenting recovery steps as they are performed?", options:["It supports later review, repeatability, and confirmation that recovery was completed correctly","It ensures that the recovery process can never be reviewed or audited by anyone in the future","It guarantees that the recovered systems will never require any monitoring after the recovery ends","It removes the need to validate that the recovered systems are actually clean before they are used"], correct:0, explanation:"Documenting recovery steps supports review, repeatability, and confirmation of correct completion." },
  { id:80470, domain:2, level:2, question:"Why should user access be reviewed before fully restoring systems in recovery?", options:["User access reviews are only ever relevant during the preparation phase and never during recovery","Attackers may have created or modified accounts that must be removed before normal use resumes","Restoring systems first and reviewing access much later is always the safest possible approach used","User access has no bearing on recovery because attackers never create or alter any accounts at all"], correct:1, explanation:"Reviewing access catches attacker-created or modified accounts before normal use resumes." },
  { id:80471, domain:2, level:3, question:"What is a reason to keep affected systems under heightened logging after recovery?", options:["Heightened logging guarantees that no attacker can ever return to the recovered systems at all","Extra logging is only useful before an incident and provides no value at all after any recovery","Detailed logs improve the chance of quickly detecting any attacker return or residual compromise","Heightened logging removes the need to validate that the recovered systems were properly cleaned"], correct:2, explanation:"Heightened logging improves detection of attacker return or residual compromise after recovery." },
  { id:80472, domain:2, level:2, question:"Why should recovery decisions involve business stakeholders?", options:["Business stakeholders should never be involved in any technical recovery decisions at any point","Involving stakeholders guarantees that the recovery will always finish faster than it otherwise would","Stakeholders decide the technical steps of recovery instead of the incident response handlers","They understand operational priorities and can help balance restoration speed against overall risk"], correct:3, explanation:"Stakeholders provide operational priorities to balance restoration speed against risk; not technical steps." },
  { id:80473, domain:2, level:1, question:"What is a purpose of a post-incident timeline reconstruction?", options:["It clarifies how the incident unfolded so that gaps and improvement opportunities become visible","It assigns definitive personal blame to whoever failed to detect the incident sooner than they did","It guarantees that the exact same incident will be prevented from ever recurring in the future again","It replaces the need to produce any final incident report or set of recommendations for the incident"], correct:0, explanation:"Timeline reconstruction reveals how the incident unfolded and where improvements are needed." },
  { id:80474, domain:2, level:3, question:"Why should post-incident findings be shared with relevant teams?", options:["Findings should always be kept entirely secret so that no other team can ever learn from them at all","Sharing findings spreads knowledge so other teams can strengthen their own defenses and processes","Sharing findings guarantees that no similar incident can ever occur anywhere in the organization","Findings only ever need to be shared with the attacker involved so that they understand the response"], correct:1, explanation:"Sharing findings spreads knowledge so other teams strengthen defenses; secrecy limits learning." },
  { id:80475, domain:2, level:2, question:"What is a reason to update detection rules as a post-incident activity?", options:["Detection rules should never be changed once they are written regardless of any incident that occurs","Updating detection rules guarantees that the organization will never face any future incidents at all","Insights from the incident can improve detection so similar attacks are caught earlier next time","Detection rule updates are only ever relevant during recovery and never during post-incident work"], correct:2, explanation:"Incident insights improve detection so similar attacks are caught earlier in the future." },
  { id:80476, domain:2, level:2, question:"Why should the cost and impact of an incident be documented post-incident?", options:["It guarantees that the organization will never again need to spend any money on its security program in this scenario","It ensures that the same incident will recur so that the documented costs can be compared over time","It replaces the need to conduct any lessons-learned review after the security incident concludes","It supports future risk decisions, budget justification, and communication with leadership and boards"], correct:3, explanation:"Documenting cost and impact supports risk decisions, budgeting, and leadership communication." },
  { id:80477, domain:2, level:2, question:"What is a benefit of validating that recommended improvements are implemented?", options:["It ensures that lessons learned translate into real changes rather than remaining unaddressed on paper","It guarantees that no further incidents of any kind will ever affect the organization going forward","It removes the need to ever review the incident response plan again after the improvements are noted in this scenario","It ensures that the recommendations are archived and then deliberately never acted upon by anyone"], correct:0, explanation:"Validating implementation ensures lessons learned become real changes, not just paper recommendations." },
  { id:80478, domain:2, level:1, question:"Why is it important to formally close an incident rather than leaving it open indefinitely?", options:["Leaving incidents open indefinitely guarantees that they can never possibly recur in the future","Formal closure confirms all work is complete, records are finalized, and resources can be released","Formal closure requires deleting all of the records and evidence associated with the incident handled","Closing an incident is unnecessary because incidents naturally resolve themselves over enough time"], correct:1, explanation:"Formal closure confirms completed work and finalized records; it does not require deleting anything." },
  { id:80479, domain:2, level:2, question:"What is the incident handler's responsibility regarding chain of custody?", options:["Allowing anyone on the team to modify the evidence freely as long as the handler is informed later","Transferring all evidence to the attacker for safekeeping until the investigation has been completed","Ensuring evidence is properly documented, transferred, and stored to maintain its integrity","Ignoring chain of custody entirely because it only matters during the preparation phase of response"], correct:2, explanation:"Handlers ensure documented, controlled evidence handling to maintain integrity throughout." },
  { id:80480, domain:2, level:2, question:"What is the incident handler's role in prioritizing multiple concurrent incidents?", options:["Handling every concurrent incident with identical urgency regardless of its actual business impact","Ignoring all but the first incident that was reported until that one has been fully resolved first","Randomly choosing which incident to work on so that no bias affects the prioritization decision made","Assessing each incident's impact and urgency to allocate limited resources where they matter most"], correct:3, explanation:"Handlers prioritize by impact and urgency to allocate scarce resources effectively." },
  { id:80481, domain:2, level:2, question:"Why must the incident handler follow established procedures rather than improvising?", options:["Consistent, documented procedures reduce errors and support defensible, repeatable response actions","Improvising is always superior because established procedures slow down every incident response","Following procedures guarantees that no incident will ever require any escalation to management again","Established procedures exist only to satisfy auditors and provide no real value during a real incident"], correct:0, explanation:"Following procedures reduces errors and supports defensible, repeatable actions under pressure." },
  { id:80482, domain:2, level:2, question:"What is the incident handler's role in ensuring evidence is not contaminated?", options:["Freely sharing evidence access with all staff so that everyone can inspect and modify it as needed","Using sound forensic methods and controlled handling so evidence remains reliable and admissible","Working directly on the original evidence media to ensure the fastest possible analysis every time","Skipping documentation of evidence handling to reduce the overall workload during the investigation"], correct:1, explanation:"Sound forensic methods and controlled handling keep evidence reliable and admissible." },
  { id:80483, domain:2, level:1, question:"How does the incident handler contribute during the preparation phase specifically?", options:["By responding to and resolving incidents that have not yet been detected anywhere in the environment","By deleting old incident records in bulk so that the tracking system remains completely empty always","By helping build playbooks, arranging training, and ensuring tools and access are ready in advance","By approving all organizational budgets unrelated to the security program during the preparation phase"], correct:2, explanation:"Handlers build playbooks, training, and readiness in preparation; they cannot resolve undetected incidents." },
  { id:80484, domain:2, level:2, question:"Why should the incident handler verify assumptions with evidence during an incident?", options:["Assumptions are always correct during incidents, so verifying them with evidence just wastes time","Verifying assumptions guarantees that the incident will be closed as a false positive every time","Handlers should rely only on assumptions because gathering evidence slows the response too much","Acting on unverified assumptions can lead to incorrect containment or missed compromised systems"], correct:3, explanation:"Unverified assumptions can misdirect containment or miss compromised systems; evidence is essential." },
  { id:80485, domain:2, level:2, question:"What is a handler's key responsibility when handing off an incident between shifts?", options:["Providing a clear status update, current actions, and outstanding tasks so response continuity is kept","Closing the incident before the shift ends so that the next shift has nothing at all to work on later in this scenario","Withholding all details from the incoming shift so that they can form fully independent conclusions","Deleting the incident record so that the incoming shift starts the entire investigation from scratch"], correct:0, explanation:"Handoffs need clear status and outstanding tasks to preserve continuity; not closure or withholding." },
  { id:80486, domain:2, level:2, question:"Why is stakeholder communication a recurring handler responsibility across phases?", options:["Stakeholders only ever need to be contacted once, at the very start, and never again after that point","Stakeholders need timely, accurate updates to make decisions and manage risk throughout the incident","Communication with stakeholders is the sole responsibility of the marketing team during every incident","Handlers should avoid all stakeholder communication so that they can focus purely on technical work"], correct:1, explanation:"Stakeholders need ongoing accurate updates to decide and manage risk across every phase." },
  { id:80487, domain:2, level:2, question:"What is a preparation activity that supports faster incident triage later?", options:["Ensuring that no criteria exist so that each analyst can classify incidents however they personally like","Deleting all historical incident data so that triage decisions are never influenced by any past events","Establishing clear categorization and severity criteria so incidents can be classified consistently","Requiring executive approval before any incident can be triaged at all during the response process"], correct:2, explanation:"Predefined categorization and severity criteria support consistent, faster triage later on." },
  { id:80488, domain:2, level:1, question:"Why should incident response tools be validated and updated during preparation?", options:["Response tools never require any updates or validation because they always work correctly forever","Validating tools guarantees that no incident will ever occur that those tools cannot fully handle alone","Tool validation is only relevant after an incident and provides no value during the preparation phase","Outdated or untested tools may fail during an incident when they are needed the most by the team"], correct:3, explanation:"Outdated or untested tools may fail when needed, so validation and updates happen in preparation." },
  { id:80489, domain:2, level:2, question:"What is the value of conducting a threat assessment during preparation?", options:["It helps prioritize defenses and readiness against the threats most likely to target the organization","It guarantees that the organization will be able to fully prevent every conceivable attack in advance","It removes the need to triage or prioritize any incidents once they actually begin to occur later","It ensures that all threats are treated as equally likely regardless of the organization actual risk"], correct:0, explanation:"A threat assessment prioritizes readiness against likely threats; it cannot prevent all attacks." },
  { id:80490, domain:2, level:2, question:"Why is it useful to identify critical business processes during preparation?", options:["It guarantees that none of the critical business processes can ever be disrupted by an incident at all","It lets responders prioritize protecting and recovering the processes most vital to the business first","It removes the need to assess the impact of any incident on the business during the triage phase later","It ensures that every business process is treated as equally critical during any incident response"], correct:1, explanation:"Identifying critical processes lets responders prioritize protecting and recovering the most vital first." },
  { id:80491, domain:2, level:2, question:"What is a benefit of predefined severity and priority matrices during triage?", options:["They ensure that every incident always receives the maximum possible severity and priority ratings","They fully remove the need for any handler judgment when classifying incidents during the triage step","They enable consistent, objective classification so incidents are handled with appropriate urgency","They guarantee that no incident will ever need to be re-prioritized once it has first been classified"], correct:2, explanation:"Matrices enable consistent, objective classification; they still allow judgment and re-prioritization." },
  { id:80492, domain:2, level:2, question:"Why should a handler confirm whether an incident is ongoing or historical during triage?", options:["The timing of an incident has no effect at all on how it should be triaged or handled by the team","Historical incidents always require more urgent containment than any ongoing active incident does","Confirming timing removes the need to categorize or assess the impact of the incident during triage in this scenario","Ongoing incidents demand immediate containment while historical ones focus on scope and investigation"], correct:3, explanation:"Ongoing incidents need immediate containment; historical ones center on scope and investigation." },
  { id:80493, domain:2, level:1, question:"What is a reason to escalate an incident that exceeds the handler's authority?", options:["Some response actions require higher approval, and escalation ensures decisions are properly authorized","Escalation is only ever used to shift blame away from the handler onto the management team involved","Handlers should never escalate any incident because doing so always slows down the entire response","Escalation guarantees that the incident will automatically be downgraded to the lowest severity level in this scenario"], correct:0, explanation:"Escalation ensures actions beyond the handler's authority are properly approved by decision-makers." },
  { id:80494, domain:2, level:2, question:"Why should containment measures be reversible where possible?", options:["Irreversible measures are always preferable because they guarantee that the threat can never return in this scenario","Reversible measures let the team adjust if new information changes the understanding of the incident","Reversibility of containment measures has no relevance at all to the incident response process","Containment measures should always be permanent so that the recovery phase can be skipped entirely"], correct:1, explanation:"Reversible containment lets the team adapt as understanding of the incident evolves." },
  { id:80495, domain:2, level:2, question:"What is a benefit of coordinating containment with the affected system owners?", options:["Owners should be excluded so that containment can be applied without any operational considerations","Coordinating with owners guarantees that no evidence will need to be preserved during the containment","Owners can advise on dependencies and minimize disruption while containment measures are applied","System owners are responsible for choosing the forensic tools used during the incident investigation"], correct:2, explanation:"Owners advise on dependencies to minimize disruption during containment; they do not pick forensic tools." },
  { id:80496, domain:2, level:2, question:"Why is verifying backup integrity important before relying on it during recovery?", options:["Backups never require any verification because they are always complete and clean by their nature","Verifying backups guarantees that the restored systems will never require any monitoring afterward in this scenario","Backup verification is only relevant during preparation and provides no value during any recovery","A corrupted or infected backup could reintroduce the threat or fail to restore the systems correctly"], correct:3, explanation:"Unverified backups may be corrupt or infected, reintroducing threats or failing to restore correctly." },
  { id:80497, domain:2, level:2, question:"Why should incident response metrics be defined before incidents occur?", options:["Defined metrics let the team measure response performance consistently and identify improvements","Metrics defined in advance guarantee that no incident will ever exceed the response time targets set","Predefined metrics remove the need to ever review the incident response plan after any real incident","Metrics only matter to auditors and provide no operational value to the response team during events"], correct:0, explanation:"Predefined metrics enable consistent measurement and improvement; they cannot guarantee target times." },
  { id:80498, domain:2, level:1, question:"What is a benefit of retaining incident records for a defined retention period?", options:["Retaining records guarantees that identical incidents will never occur again anywhere in the future","Retained records support audits, legal needs, trend analysis, and handling of any recurring incidents","Record retention removes the need to produce any final incident report at the close of the incident","Records should be deleted immediately after closure to keep the tracking system as small as possible in this scenario"], correct:1, explanation:"Retention supports audits, legal needs, and trend analysis; records should not be deleted immediately." },
  { id:80499, domain:2, level:2, question:"Why should the handler distinguish between containment, eradication, and recovery goals?", options:["The three phases are entirely identical, so distinguishing between their goals is never truly necessary","Distinguishing the phases guarantees that no monitoring will be required after the incident concludes","Each phase has a distinct objective, and confusing them can leave threats present or delay operations","The phases only matter for reporting purposes and have no effect on the actual response actions taken"], correct:2, explanation:"Each phase has a distinct objective; confusing them leaves threats present or delays operations." },
  { id:80500, domain:2, level:2, question:"What is a benefit of a well-defined incident escalation and communication plan?", options:["It guarantees that every incident will always be escalated straight to the board regardless of impact","It removes the need to categorize or prioritize any incident during the triage phase of the response","It ensures that technical responders are kept entirely uninformed about the incident being handled","It ensures the right people are informed and involved promptly so decisions are made without delay"], correct:3, explanation:"A clear escalation and communication plan gets the right people involved promptly for timely decisions." },
];
